{% extends '@PrestaShop/Admin/layout.html.twig' %}
{% set layoutHeaderToolbarBtn = {
  add: {
    href: path('admin_attributes_create', { 'attributeGroupId': attributeGroupId}),
    desc: 'Add new value'|trans({}, 'Admin.Catalog.Feature'),
    icon: 'add_circle_outline',
  }
}
%}

{% block content %}
  {% block attributes_listing %}
    {% embed '@PrestaShop/Admin/Common/Grid/grid_panel.html.twig' with {'grid': attributeGrid} %}
      {% block grid_panel_footer %}
        <div class=\"card-footer\">
          <a href=\"{{ path('admin_attribute_groups_index') }}\" class=\"btn btn-outline-secondary\">
            <i class=\"material-icons rtl-flip\">arrow_back</i>
            {{ 'Back to list'|trans({}, 'Admin.Actions') }}
          </a>
        </div>
      {% endblock %}
    {% endembed %}
  {% endblock %}
{% endblock %}

{% block javascripts %}
  {{ parent() }}

  <script src=\"{{ asset('themes/default/js/bundle/pagination.js') }}\"></script>
  <script src=\"{{ asset('themes/new-theme/public/attribute.bundle.js') }}\"></script>
{% endblock %}
", "@PrestaShop/Admin/Sell/Catalog/Attribute/index.html.twig", "/var/www/html/src/PrestaShopBundle/Resources/views/Admin/Sell/Catalog/Attribute/index.html.twig");
    }
}


